begin

    process(pixel_row, pixel_col, chefm_x, chefm_y)
        variable px : integer;
        variable py : integer;
        variable cx : integer;
        variable cy : integer;
        variable sx : integer;
        variable sy : integer;
        variable color_idx : std_logic_vector(3 downto 0);
    begin
        red   <= "0000";
        green <= "0000";
        blue  <= "0000";
        visible <= '0';   -- default OFF

        px := to_integer(unsigned(pixel_col));
        py := to_integer(unsigned(pixel_row));
        cx := to_integer(unsigned(chefm_x));
        cy := to_integer(unsigned(chefm_y));

        if (px >= cx and px < cx + CHEFF_W and
            py >= cy and py < cy + CHEFF_H) then

            sx := (px - cx) / 2;
            sy := (py - cy) / 2;

            color_idx := CHEFF_SPRITE(sy)(sx);

            if color_idx /= "0000" then
                visible <= '1';
            end if;

            case color_idx is
                when "0000" => -- transparent/background
                    red   <= "0000";
                    green <= "0000";
                    blue  <= "0000";

                when "0001" => -- black
                    red   <= "0000";
                    green <= "0000";
                    blue  <= "0000";
                    
                when "0101" => -- white
                    red   <= "1111";
                    green <= "1111";
                    blue  <= "1111";

                when "0110" => -- light grey
                    red   <= "1100";
                    green <= "1100";
                    blue  <= "1100";

                when "0111" => -- medium grey
                    red   <= "1000";
                    green <= "1000";
                    blue  <= "1000";

                when "1000" => -- skin tone
                    red   <= "1111";
                    green <= "1100";
                    blue  <= "0111";

                when others =>
                    red   <= "0000";
                    green <= "0000";
                    blue  <= "0000";
            end case;
        end if;
    end process;

end Behavioral;